class Board:
    def __init__(self):
        self.board = self._initialize_board()

    def _initialize_board(self):
        board = [[' ' for _ in range(8)] for _ in range(8)]
        pieces = ['r', 'b']
        for color in pieces:
            if color == 'r':
                row_range = (0, 2)
            else:
                row_range = (5, 7)

            for row in row_range:
                for col in range(8):
                    if (row + col) % 2 != 0:
                        board[row][col] = color
        return board

    def print_board(self):
        print("   A B C D E F G H")
        for i, row in enumerate(self.board, start=1):
            print(f"{i} |{'|'.join(row)}|")

    def move_piece(self, from_pos, to_pos):
        x1, y1 = from_pos
        x2, y2 = to_pos
        self.board[x2][y2] = self.board[x1][y1]
        self.board[x1][y1] = ' '

    def is_valid_move(self, from_pos, to_pos):
        # Basic move validation (no capture logic for now)
        x1, y1 = from_pos
        x2, y2 = to_pos
        if abs(x2 - x1) != 1 or abs(y2 - y1) != 1:
            return False
        if self.board[x2][y2] != ' ':
            return False
        return True

    def king_piece(self, pos):
        x, y = pos
        if (x == 0 and self.board[x][y] == 'r') or (x == 7 and self.board[x][y] == 'b'):
            self.board[x][y] += 'K'
```

