class Player:
    def __init__(self, color):
        self.color = color

    def get_valid_moves(self, board):
        valid_moves = []
        for row in range(8):
            for col in range(8):
                if (board.board[row][col] == 'r' or board.board[row][col] == 'bk') and row > 0:
                    if col > 0 and board.board[row-1][col-1] == ' ':
                        valid_moves.append(((row, col), (row-1, col-1)))
                    if col < 7 and board.board[row-1][col+1] == ' ':
                        valid_moves.append(((row, col), (row-1, col+1)))
        return valid_moves

    def make_move(self, from_pos, to_pos, board):
        board.move_piece(from_pos, to_pos)
```

**game.py**
```python
from board import Board
from player import Player
import utils

class Game:
    def __init__(self):
        self.board = Board()
        self.players = {'r': Player('red'), 'b': Player('black')}
        self.current_player = 'r'

    def play(self):
        while True:
            self.board.print_board()
            valid_moves = self.players[self.current_player].get_valid_moves(self.board)
            if not valid_moves:
                print(f"{self.current_player.capitalize()} player has no valid moves. Game over!")
                break

            from_pos, to_pos = utils.parse_position(input(f"{self.current_player} player, enter move (e.g., A1-B2): "))
            if (from_pos, to_pos) in valid_moves:
                self.players[self.current_player].make_move(from_pos, to_pos, self.board)
                if self.current_player == 'r':
                    self.current_player = 'b'
                else:
                    self.current_player = 'r'
            else:
                print("Invalid move. Please try again.")

if __name__ == "__main__":
    game = Game()
    game.play()
```

